// Parse incoming capture data
const capture = $input.first().json;

// Extract base64 image (remove data URL prefix)
const screenshot = capture.screenshot || '';
const base64Data = screenshot.replace(/^data:image\/\w+;base64,/, '');

// Determine source type for task naming
let sourceType = 'Web';
const domain = capture.source?.domain?.toLowerCase() || '';

if (domain.includes('linkedin')) sourceType = 'LinkedIn';
else if (domain.includes('facebook')) sourceType = 'Facebook';
else if (domain.includes('outlook') || domain.includes('mail')) sourceType = 'Email';
else if (domain.includes('google')) sourceType = 'Google';

// Build task name
const taskName = `${sourceType} Capture: ${capture.contact?.name || 'Unknown'}`;

// Build task description
const description = [
  `**Source:** ${capture.source?.url || 'Unknown'}`,
  `**Page Title:** ${capture.source?.title || 'Unknown'}`,
  `**Captured:** ${capture.capturedAt || new Date().toISOString()}`,
  capture.note ? `\n**Note:** ${capture.note}` : ''
].filter(Boolean).join('\n');

return [{
  json: {
    taskName,
    description,
    contactId: capture.contact?.id,
    contactName: capture.contact?.name,
    contactEmail: capture.contact?.email,
    sourceUrl: capture.source?.url,
    sourceDomain: capture.source?.domain,
    sourceType,
    note: capture.note,
    capturedAt: capture.capturedAt,
    screenshotBase64: base64Data,
    screenshotMimeType: 'image/png'
  }
}];
